@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
    </div>
}
else if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <!-- Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold">@allTasks.Count</div>
                    <small class="text-muted">Total</small>
                </div>
            </div>
        </div>
        @foreach (var col in columns)
        {
            <div class="col">
                <div class="card text-center">
                    <div class="card-body py-2">
                        <div class="fw-bold">@GetTasksForColumn(col).Count</div>
                        <small class="text-muted">@col</small>
                    </div>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center border-danger">
                <div class="card-body py-2">
                    <div class="fw-bold text-danger">@allTasks.Count(t => t.DueDate < DateTime.Today)</div>
                    <small class="text-muted">Overdue</small>
                </div>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @for (int i = 0; i < columns.Length; i++)
        {
            var colIndex = i;
            var colName = columns[colIndex];
            var colTasks = GetFilteredTasksForColumn(colName);

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@colName</strong>
                        <span class="badge bg-secondary">@colTasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 p-2" style="min-height: 200px;">
                        @foreach (var task in colTasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <div class="fw-semibold mb-1">@task.Title</div>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <small class="text-muted">@task.Assignee</small>
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                    </div>
                                    <div class="d-flex justify-content-between align-items-center">
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                        <div>
                                            @if (colIndex > 0)
                                            {
                                                <button class="btn btn-outline-secondary btn-sm me-1"
                                                        @onclick="() => MoveTaskAsync(task.Id, columns[colIndex - 1])"
                                                        disabled="@isMoving">
                                                    &larr; Move Left
                                                </button>
                                            }
                                            @if (colIndex < columns.Length - 1)
                                            {
                                                <button class="btn btn-outline-secondary btn-sm"
                                                        @onclick="() => MoveTaskAsync(task.Id, columns[colIndex + 1])"
                                                        disabled="@isMoving">
                                                    Move Right &rarr;
                                                </button>
                                            }
                                        </div>
                                    </div>
                                </div>
                            </div>
                        }

                        <!-- Add Task Form / Button -->
                        @if (addingToColumn == colName)
                        {
                            <div class="card border-primary mt-auto">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2"
                                           @bind="newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm flex-fill"
                                                @onclick="SaveNewTaskAsync" disabled="@isSaving">
                                            @if (isSaving)
                                            {
                                                <span class="spinner-border spinner-border-sm me-1"></span>
                                            }
                                            Save
                                        </button>
                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                @onclick="CancelAdd" disabled="@isSaving">
                                            Cancel
                                        </button>
                                    </div>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-primary btn-sm mt-auto"
                                    @onclick="() => StartAdd(colName)">
                                + Add Task
                            </button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private bool isMoving;
    private bool isSaving;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    // Add-task form state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetTasksForColumn(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForColumn(string status) =>
        allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(searchQuery) ||
                         t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        isMoving = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                allTasks[idx] = allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isMoving = false;
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => addingToColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || addingToColumn is null)
            return;

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);
            // CreateTaskAsync returns a task with default status; update to match the target column
            if (created.Status != addingToColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, addingToColumn);
                created = created with { Status = addingToColumn };
            }
            allTasks.Add(created);
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }
}

